function validateRegistration(req, res, next) {
  const { email, password, name } = req.body;
  const invalidFields = [];

  if (!email || !email.includes('@')) invalidFields.push('email');
  if (!password || password.length < 8) invalidFields.push('password');
  if (!name || name.length < 2) invalidFields.push('name');

  if (invalidFields.length > 0) {
    return res.status(400).json({ error: 'Validation failed', fields: invalidFields });
  }
  next();
}

